def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 20):
            if j % 4 == 0:
                factor = 1.3
            elif j % 5 == 0:
                factor = 1.15
            elif j % 2 == 0:
                factor = 1.05
            else:
                factor = 0.85
            term = factor * (1 / (j**3)) * (ratio ** j)
            score += term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.07 * capacity:
            score *= 1.8
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.3 * capacity:
            score *= 1.0
        else:
            score *= 0.6
        mods = [int(capacity) % x == 0 for x in (2, 3, 5, 7, 11)]
        mod_count = sum(mods)
        if mod_count >= 3:
            score -= 0.2 * (capacity / 12)
        elif mod_count == 2:
            score -= 0.15 * (capacity / 20)
        elif mod_count == 1:
            if mods[0]:
                score -= 0.05 * (capacity / 15)
            elif mods[1]:
                score -= 0.07 * (capacity / 18)
            elif mods[2]:
                score -= 0.1 * (capacity / 25)
            elif mods[3]:
                score -= 0.12 * (capacity / 30)
            elif mods[4]:
                score -= 0.09 * (capacity / 35)
        else:
            score -= 0.04 * (capacity / 40)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.012 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 1.5 * threshold:
                penalty += 0.12 * k
            elif diff < 3 * threshold:
                penalty -= 0.08 * k
            else:
                penalty -= 0.1 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            multi_factor = 1
            for m in range(1, 5):
                frac = capacity / m
                if abs(frac - item) < 0.015 * frac:
                    multi_factor += 0.06 * m
                else:
                    multi_factor -= 0.02 * m
            score *= max(1, multi_factor)
        if score > 3:
            score = 3
        if score < 0.1:
            score += 0.1
        priorities[i] = score
    return priorities
